USE [DeineDatenbank];
GO

/*
===============================================================================
Objekt       : monitor.VW_AnalysisCatalog
Version      : 1.0.0
Stand        : 2026-07-21
Typ          : View
Zweck        : Katalogisiert jede öffentliche Framework-Procedure nach
               Anwenderrolle, Themenbereich, Scope, Evidenzart, Kostenprofil,
               Voraussetzung, Paketgrenze und sicherem Einstieg.
Semantik     : Genau eine Zeile je öffentlicher Procedure aus dem
               Objektinventar. Eine Procedure besitzt genau eine primäre
               Navigationsrolle; Mehrfachzuordnungen erfolgen über Suchbegriffe
               und Relationen, nicht über zusätzliche Katalogzeilen.
Kosten       : CostRangeCode beschreibt die dokumentierte Spannweite.
               RepresentativeAnalysisClass verweist, sofern vorhanden, auf
               monitor.VW_AnalyseClassCatalog und ersetzt nicht die
               pfadabhängigen Gates der Ziel-Procedure.
Eigenlast    : Konstante Frameworkmetadaten; keine DMVs, Benutzerkataloge oder
               produktiven Datenzugriffe.
===============================================================================
*/
CREATE OR ALTER VIEW [monitor].[VW_AnalysisCatalog]
AS
    SELECT
          CONVERT(sysname, [v].[ProcedureName]) AS [ProcedureName]
        , CONVERT(nvarchar(160), [v].[DisplayName]) AS [DisplayName]
        , CONVERT(varchar(40), [v].[PrimaryAreaCode]) AS [PrimaryAreaCode]
        , CONVERT(nvarchar(160), [v].[PrimaryAreaName]) AS [PrimaryAreaName]
        , CONVERT(varchar(24), [v].[NavigationRole]) AS [NavigationRole]
        , CONVERT(varchar(40), [v].[ScopeCode]) AS [ScopeCode]
        , CONVERT(varchar(40), [v].[EvidenceType]) AS [EvidenceType]
        , CONVERT(varchar(32), [v].[CostRangeCode]) AS [CostRangeCode]
        , CONVERT(varchar(64), [v].[RepresentativeAnalysisClass]) AS [RepresentativeAnalysisClass]
        , CONVERT(bit, [v].[RequiresKnownTarget]) AS [RequiresKnownTarget]
        , CONVERT(bit, [v].[RequiresHighImpactForSafeStart]) AS [RequiresHighImpactForSafeStart]
        , CONVERT(bit, [v].[HighImpactPathAvailable]) AS [HighImpactPathAvailable]
        , CONVERT(varchar(32), [v].[PackageCode]) AS [PackageCode]
        , CONVERT(smallint, [v].[DefaultRank]) AS [DefaultRank]
        , CONVERT(nvarchar(1000), [v].[Purpose]) AS [Purpose]
        , CONVERT(nvarchar(1000), [v].[PrerequisiteSummary]) AS [PrerequisiteSummary]
        , CONVERT(nvarchar(2000), [v].[SafeCall]) AS [SafeCall]
        , CONVERT(nvarchar(400), [v].[DocumentationPath]) AS [DocumentationPath]
        , CONVERT(nvarchar(400), [v].[RunbookPath]) AS [RunbookPath]
    FROM
    (
        VALUES
          (N'USP_AnalysisNavigator',N'Analyseweg finden','NAVIGATION',N'Einstieg und Orientierung','ENTRY','FRAMEWORK','FRAMEWORK_METADATA','LOW',NULL,0,0,0,'CORE',NULL,N'Findet passende Framework-Procedures nach Symptom, Ziel, Scope oder Fachbegriff, ohne eine Diagnose auszuführen.',N'Keine fachliche Voraussetzung; der Katalog liest ausschließlich statische Frameworkmetadaten.',N'EXEC [monitor].[USP_AnalysisNavigator];',N'Documentation/Analysis_Guides/Procedures/USP_AnalysisNavigator.md',NULL)
        , (N'USP_CheckAnalyseAccess',N'Analysefreigaben prüfen','FRAMEWORK',N'Framework und Zugriff','SETUP','FRAMEWORK','FRAMEWORK_METADATA','LOW',NULL,0,0,0,'CORE',NULL,N'Zeigt die interne Gruppen- und Analyseklassenfreigabe des aktuellen Sicherheitskontexts.',N'Nur für Ressourcenfreigaben; die Ausgabe ersetzt keine SQL-Server-Berechtigungsprüfung.',N'EXEC [monitor].[USP_CheckAnalyseAccess] @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CheckAnalyseAccess.md',NULL)
        , (N'USP_CheckFrameworkCapabilities',N'Framework-Capabilities prüfen','FRAMEWORK',N'Framework und Zugriff','SETUP','FRAMEWORK','FRAMEWORK_METADATA','LOW_MEDIUM',NULL,0,0,0,'CORE',NULL,N'Prüft Version, Policy, Berechtigung, Abfragbarkeit und Featurestatus für Diagnosepfade.',N'Sichtbarkeit und Rechte bestimmen die Vollständigkeit; die Procedure vergibt keine Rechte.',N'EXEC [monitor].[USP_CheckFrameworkCapabilities] @NurNichtVerfuegbar = 1, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CheckFrameworkCapabilities.md',NULL)
        , (N'USP_PrepareDatabaseCandidates',N'Datenbankauswahl vorbereiten','FRAMEWORK',N'Framework und Zugriff','SUPPORT','FRAMEWORK','FRAMEWORK_METADATA','LOW',NULL,1,0,0,'CORE',NULL,N'Befüllt eine vom Aufrufer bereitgestellte temporäre Kandidatenliste nach dem zentralen Datenbankvertrag.',N'Interner Aufrufvertrag für Framework-Procedures; kein eigenständiger Diagnoseeinstieg.',N'EXEC [monitor].[USP_AnalysisNavigator] @Suchbegriff = N''USP_PrepareDatabaseCandidates'';',N'Documentation/Analysis_Guides/Procedures/USP_PrepareDatabaseCandidates.md',NULL)
        , (N'USP_PrepareNameFilters',N'Namensfilter vorbereiten','FRAMEWORK',N'Framework und Zugriff','SUPPORT','FRAMEWORK','FRAMEWORK_METADATA','LOW',NULL,1,0,0,'CORE',NULL,N'Validiert und zerlegt case-sensitive, bracket-aware Namensfilter für aufrufende Procedures.',N'Interner Aufrufvertrag; der Aufrufer muss die vorgesehenen lokalen Zieltabellen bereitstellen.',N'EXEC [monitor].[USP_AnalysisNavigator] @Suchbegriff = N''USP_PrepareNameFilters'';',N'Documentation/Analysis_Guides/Procedures/USP_PrepareNameFilters.md',NULL)

        , (N'USP_CurrentSessions',N'Aktuelle Sessions','LIVE',N'Akute Störung und laufende Requests','FOLLOW_UP','SESSION_REQUEST','LIVE_SNAPSHOT','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',NULL,N'Inventarisiert Sessions, Verbindungskontext, kumulative Aktivität und offene Transaktionen.',N'Flüchtiger Snapshot; Session- und Clientangaben können sich unmittelbar ändern.',N'EXEC [monitor].[USP_CurrentSessions] @MitSqlText = 0, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentSessions.md',NULL)
        , (N'USP_CurrentRequests',N'Aktive Requests und Ressourcen','LIVE',N'Akute Störung und laufende Requests','ENTRY','SESSION_REQUEST','LIVE_SNAPSHOT','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',3,N'Ordnet laufende Requests nach Laufzeit, CPU, I/O, Wait, Blocking, Memory Grant und Ausführungskontext ein.',N'Nur aktuell laufende Requests; für vergangene Regressionen Query Store oder Extended Events verwenden.',N'EXEC [monitor].[USP_CurrentRequests] @MaxZeilen = 50, @MitSqlText = 0, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentRequests.md',N'Documentation/Analysis_Guides/Runbooks/02_High_CPU.md')
        , (N'USP_CurrentBlocking',N'Aktuelle Blocking-Ketten','LIVE',N'Akute Störung und laufende Requests','ENTRY','SESSION_REQUEST','LIVE_SNAPSHOT','LOW_HIGH_OPT_IN','STANDARD_CURRENT',0,0,1,'CORE',2,N'Rekonstruiert aktuelle Blockingkanten, Root Blocker und bei Bedarf technische Lockressourcen.',N'Blocking muss während des Snapshots noch bestehen; Lockdetails sind ein expliziter High-Impact-Pfad.',N'EXEC [monitor].[USP_CurrentBlocking] @MinWaitMs = 1000, @BlockingObjektTiefe = ''STANDARD'', @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentBlocking.md',N'Documentation/Analysis_Guides/Runbooks/01_User_Hangs_Blocking.md')
        , (N'USP_CurrentWaits',N'Aktuelle und gesampelte Waits','LIVE',N'Akute Störung und laufende Requests','FOLLOW_UP','SERVER','SAMPLE_DELTA','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',NULL,N'Zeigt aktuelle Tasks, kumulative Waits und optional ein kurzes Wait-Delta.',N'Waits sind Symptome; Scope, Dauer, Workload und Gegenprobe bestimmen die Interpretation.',N'EXEC [monitor].[USP_CurrentWaits] @SampleSeconds = 5, @MitSqlText = 0, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentWaits.md',NULL)
        , (N'USP_CurrentTransactions',N'Offene und alte Transaktionen','LIVE',N'Akute Störung und laufende Requests','FOLLOW_UP','SESSION_REQUEST','LIVE_SNAPSHOT','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',NULL,N'Zeigt offene Transaktionen, Alter, Sessionzustand, Logverbrauch und optionalen SQL-Kontext.',N'Eine lange Transaktion kann geplant sein; Blocking, Logwachstum und Anwendungskontext gegenprüfen.',N'EXEC [monitor].[USP_CurrentTransactions] @MinAlterSekunden = 60, @MitSqlText = 0, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentTransactions.md',NULL)
        , (N'USP_CurrentMemoryGrants',N'Wartende und aktive Memory Grants','LIVE',N'Akute Störung und laufende Requests','ENTRY','SESSION_REQUEST','LIVE_SNAPSHOT','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',14,N'Zeigt angeforderte, gewährte und genutzte Query Execution Memory Grants.',N'Ein großer Grant ist ohne Warteschlange, Nutzung, Plan und Konkurrenz kein Fehlerbeweis.',N'EXEC [monitor].[USP_CurrentMemoryGrants] @NurWartende = 1, @MitSqlText = 0, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentMemoryGrants.md',N'Documentation/Analysis_Guides/Runbooks/06_Memory_Grant_Queue.md')
        , (N'USP_CurrentTempDB',N'Aktueller TempDB-Verbrauch','LIVE',N'Akute Störung und laufende Requests','ENTRY','DATABASE','LIVE_SNAPSHOT','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',7,N'Zeigt aktuelle TempDB-Belegung nach Session, Verbrauchsart und Datei.',N'User Objects, Internal Objects und Version Store benötigen unterschiedliche Folgeanalysen.',N'EXEC [monitor].[USP_CurrentTempDB] @MitDateien = 1, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentTempDB.md',N'Documentation/Analysis_Guides/Runbooks/04_TempDB_Growth.md')
        , (N'USP_CurrentIO',N'Aktuelle Datei-I/O-Latenz','LIVE',N'Akute Störung und laufende Requests','ENTRY','MULTI_DATABASE','SAMPLE_DELTA','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',9,N'Bewertet Datei-I/O kumulativ oder als kurzes Delta-Sample und kann Pending I/O ergänzen.',N'Kumulative Durchschnitte und aktuelles Sample getrennt lesen; Storage-Kausalität extern bestätigen.',N'EXEC [monitor].[USP_CurrentIO] @SampleSeconds = 5, @PendingIoEinbeziehen = 1, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentIO.md',N'Documentation/Analysis_Guides/Runbooks/07_IO_Latency.md')
        , (N'USP_CurrentLog',N'Aktuelle Transaktionslog-Auslastung','LIVE',N'Akute Störung und laufende Requests','ENTRY','MULTI_DATABASE','LIVE_SNAPSHOT','LOW_HIGH_OPT_IN','STANDARD_CURRENT',0,0,1,'CORE',8,N'Zeigt Logauslastung, Wiederverwendungswartegrund, VLF- und optional PVS-Kontext.',N'Hohe Auslastung erst mit Wiederverwendungsgrund, Transaktionen, Backup- und HA-Kontext bewerten.',N'EXEC [monitor].[USP_CurrentLog] @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentLog.md',N'Documentation/Analysis_Guides/Runbooks/05_Transaction_Log_Full.md')
        , (N'USP_CurrentOverview',N'Orchestrierter Live-Überblick','LIVE',N'Akute Störung und laufende Requests','ENTRY','SERVER','MIXED','LOW_MEDIUM','STANDARD_CURRENT',0,0,0,'CORE',1,N'Orchestriert mehrere leichte Live-Analysen für eine erste Triage des aktuellen Zustands.',N'Nicht atomare Momentaufnahmen; Childstatus vor Einzelwerten lesen und anschließend gezielt vertiefen.',N'EXEC [monitor].[USP_CurrentOverview] @MitSqlText = 0, @SampleSeconds = 0, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_CurrentOverview.md',N'Documentation/Analysis_Guides/Runbooks/01_User_Hangs_Blocking.md')

        , (N'USP_ObjectInventory',N'Objekt- und Indexinventar','OBJECT',N'Objekte, Indizes und Statistiken','TARGETED','OBJECT','CATALOG_CONFIGURATION','LOW_HIGH_OPT_IN','OBJECT_ANALYSIS_CURRENT',1,0,1,'CORE',NULL,N'Liefert Objekt- und Indexinventar mit Größe, Zeilen, Partitionierung, Kompression und Definition.',N'Datenbank- oder Objektscope angeben; breite Kataloganalyse kann High-Impact werden.',N'EXEC [monitor].[USP_ObjectInventory] @DatabaseNames = N''[ExampleDatabase]'', @SchemaNames = N''[ExampleSchema]'', @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_ObjectInventory.md',NULL)
        , (N'USP_IndexUsage',N'Indexnutzung seit Reset','OBJECT',N'Objekte, Indizes und Statistiken','ENTRY','OBJECT','CUMULATIVE_DMV','LOW_HIGH_OPT_IN','OBJECT_ANALYSIS_CURRENT',1,0,1,'CORE',NULL,N'Zeigt kumulative Read-/Write-Nutzung klassischer und optional In-Memory-Indizes.',N'Restart-, Datenbank- und Strukturresetgrenzen beachten; keine Nutzung ist kein automatischer Löschauftrag.',N'EXEC [monitor].[USP_IndexUsage] @DatabaseNames = N''[ExampleDatabase]'', @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_IndexUsage.md',N'Documentation/Analysis_Guides/Runbooks/08_Unused_Index.md')
        , (N'USP_IndexOperationalStats',N'Indexoperationen, Locks und Latches','OBJECT',N'Objekte, Indizes und Statistiken','TARGETED','OBJECT','CUMULATIVE_DMV','LOW_HIGH_OPT_IN','OBJECT_ANALYSIS_CURRENT',1,0,1,'CORE',NULL,N'Zeigt partitionsgenaue DML-, Allocation-, Lock-, Latch- und Zugriffsaktivität.',N'Gezielten Objektfilter verwenden; kumulative Zähler benötigen Reset- und Workloadkontext.',N'EXEC [monitor].[USP_IndexOperationalStats] @DatabaseNames = N''[ExampleDatabase]'', @FullObjectNames = N''[ExampleSchema].[ExampleTable]'', @NurMitAktivitaet = 1, @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_IndexOperationalStats.md',NULL)
        , (N'USP_MissingIndexes',N'Fehlende-Index-Evidenz','OBJECT',N'Objekte, Indizes und Statistiken','FOLLOW_UP','OBJECT','CUMULATIVE_DMV','LOW_MEDIUM','MISSING_INDEX_CURRENT',1,0,0,'CORE',NULL,N'Priorisiert flüchtige Missing-Index-Evidenz und erzeugt unverbindliche Entwürfe.',N'Nur Optimizer-Evidenz seit Reset; Überlappung, Schreibkosten und reale Querypläne gegenprüfen.',N'EXEC [monitor].[USP_MissingIndexes] @DatabaseNames = N''[ExampleDatabase]'', @MinUserReads = 10, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_MissingIndexes.md',NULL)
        , (N'USP_Statistics',N'Statistikzustand und Änderungen','OBJECT',N'Objekte, Indizes und Statistiken','TARGETED','OBJECT','CATALOG_CONFIGURATION','LOW_HIGH_OPT_IN','STATISTICS_TARGETED',1,0,1,'CORE',NULL,N'Inventarisiert Statistikdefinition, Sample, Änderungen und inkrementelle Details.',N'Objekt- oder Statistiksicht eingrenzen; Alter allein belegt keine problematische Statistik.',N'EXEC [monitor].[USP_Statistics] @DatabaseNames = N''[ExampleDatabase]'', @FullObjectNames = N''[ExampleSchema].[ExampleTable]'', @MaxZeilen = 100, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_Statistics.md',NULL)
