        , (N'USP_Columnstore',N'Columnstore-Rowgroups und Speicher','OBJECT',N'Objekte, Indizes und Statistiken','TARGETED','OBJECT','CATALOG_CONFIGURATION','MEDIUM_HIGH_OPT_IN','COLUMNSTORE_CURRENT',1,0,1,'CORE',NULL,N'Analysiert Columnstore-Rowgroups und optional Segmente sowie Dictionaries.',N'Objektscope setzen; Segment-, Dictionary- und Physical-Stats-Pfade sind explizite Vertiefungen.',N'EXEC [monitor].[USP_Columnstore] @DatabaseNames = N''[ExampleDatabase]'', @FullObjectNames = N''[ExampleSchema].[ExampleTable]'', @MitPhysicalStats = 0, @MitSegmenten = 0, @MitDictionaries = 0, @ResultSetArt = ''CONSOLE'';',N'Documentation/Analysis_Guides/Procedures/USP_Columnstore.md',NULL)
